import { ethers } from "ethers";

const ERC20_ABI = [
  "function approve(address spender, uint256 amount) external returns (bool)",
  "function allowance(address owner, address spender) external view returns (uint256)",
  "function balanceOf(address account) external view returns (uint256)",
  "function decimals() external view returns (uint8)",
  "function symbol() external view returns (string)",
];

const ROUTER_ABI = [
  "function getAmountsOut(uint256 amountIn, address[] calldata path) external view returns (uint256[] memory amounts)",
  "function swapExactTokensForTokens(uint256 amountIn,uint256 amountOutMin,address[] calldata path,address to,uint256 deadline) external returns (uint256[] memory amounts)",
];

const MAX_UINT256 = ethers.MaxUint256;

export class TokenSwapDApp {
  constructor({
    provider,
    signer,
    routerAddress,
    defaultSlippageBps = 50,
    deadlineSeconds = 60 * 20,
  }) {
    if (!provider) throw new Error("provider is required");
    if (!signer) throw new Error("signer is required");
    if (!routerAddress) throw new Error("routerAddress is required");

    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.defaultSlippageBps = defaultSlippageBps;
    this.deadlineSeconds = deadlineSeconds;
    this.router = new ethers.Contract(routerAddress, ROUTER_ABI, signer);
  }

  getTokenContract(tokenAddress, runner = this.signer) {
    return new ethers.Contract(tokenAddress, ERC20_ABI, runner);
  }

  async getUserAddress() {
    return await this.signer.getAddress();
  }

  async getTokenMetadata(tokenAddress) {
    const token = this.getTokenContract(tokenAddress, this.provider);
    const [decimals, symbol] = await Promise.all([
      token.decimals(),
      token.symbol(),
    ]);
    return { address: tokenAddress, decimals, symbol };
  }

  async getBalance(tokenAddress, userAddress) {
    const token = this.getTokenContract(tokenAddress, this.provider);
    return await token.balanceOf(userAddress);
  }

  async getAllowance(tokenAddress, owner, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, this.provider);
    return await token.allowance(owner, spender);
  }

  async needsApproval(tokenAddress, owner, requiredAmount, spender = this.routerAddress) {
    const allowance = await this.getAllowance(tokenAddress, owner, spender);
    return allowance < requiredAmount;
  }

  async approveMax(tokenAddress, spender = this.routerAddress) {
    const token = this.getTokenContract(tokenAddress, this.signer);
    const tx = await token.approve(spender, MAX_UINT256);
    const receipt = await tx.wait();
    return { tx, receipt };
  }

  async ensureApproval(tokenAddress, requiredAmount, owner) {
    const user = owner || (await this.getUserAddress());
    const approvalNeeded = await this.needsApproval(tokenAddress, user, requiredAmount, this.routerAddress);

    if (!approvalNeeded) {
      return { approved: false, alreadyApproved: true };
    }

    const result = await this.approveMax(tokenAddress, this.routerAddress);
    return { approved: true, alreadyApproved: false, ...result };
  }

  async getQuote(amountIn, path) {
    if (!Array.isArray(path) || path.length < 2) {
      throw new Error("path must contain at least 2 token addresses");
    }
    const amounts = await this.router.getAmountsOut(amountIn, path);
    return {
      amountIn: amounts[0],
      amountOut: amounts[amounts.length - 1],
      amounts,
      path,
    };
  }

  calculateAmountOutMin(amountOut, slippageBps = this.defaultSlippageBps) {
    const bpsDenominator = 10000n;
    const slippage = BigInt(slippageBps);
    return (BigInt(amountOut) * (bpsDenominator - slippage)) / bpsDenominator;
  }

  getDeadline() {
    return Math.floor(Date.now() / 1000) + this.deadlineSeconds;
  }

  async swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    recipient,
    slippageBps = this.defaultSlippageBps,
    path,
    deadline,
    autoApprove = true,
  }) {
    const user = recipient || (await this.getUserAddress());
    const swapPath = path || [tokenIn, tokenOut];

    if (!tokenIn || !tokenOut) throw new Error("tokenIn and tokenOut are required");
    if (!amountIn || BigInt(amountIn) <= 0n) throw new Error("amountIn must be greater than zero");
    if (!Array.isArray(swapPath) || swapPath.length < 2) {
      throw new Error("path must contain at least 2 token addresses");
    }

    const balance = await this.getBalance(tokenIn, user);
    if (balance < amountIn) {
      throw new Error("insufficient token balance");
    }

    let approvalResult = { approved: false, alreadyApproved: true };
    if (autoApprove) {
      approvalResult = await this.ensureApproval(tokenIn, amountIn, user);
    } else {
      const approvalNeeded = await this.needsApproval(tokenIn, user, amountIn, this.routerAddress);
      if (approvalNeeded) {
        throw new Error("token approval required");
      }
    }

    const quote = await this.getQuote(amountIn, swapPath);
    const amountOutMin = this.calculateAmountOutMin(quote.amountOut, slippageBps);
    const txDeadline = deadline || this.getDeadline();

    const tx = await this.router.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      swapPath,
      user,
      txDeadline
    );

    const receipt = await tx.wait();

    return {
      approval: approvalResult,
      quote,
      amountOutMin,
      tx,
      receipt,
    };
  }

  async parseAmount(tokenAddress, amount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.parseUnits(String(amount), decimals);
  }

  async formatAmount(tokenAddress, amount) {
    const { decimals } = await this.getTokenMetadata(tokenAddress);
    return ethers.formatUnits(amount, decimals);
  }
}

export async function createBrowserSwapClient({
  routerAddress,
  defaultSlippageBps,
  deadlineSeconds,
} = {}) {
  if (typeof window === "undefined" || !window.ethereum) {
    throw new Error("No injected wallet found");
  }

  const provider = new ethers.BrowserProvider(window.ethereum);
  await provider.send("eth_requestAccounts", []);
  const signer = await provider.getSigner();

  return new TokenSwapDApp({
    provider,
    signer,
    routerAddress,
    defaultSlippageBps,
    deadlineSeconds,
  });
}

export async function exampleSwap() {
  const app = await createBrowserSwapClient({
    routerAddress: "0xRouterAddressHere",
    defaultSlippageBps: 50,
    deadlineSeconds: 1200,
  });

  const tokenIn = "0xTokenInAddressHere";
  const tokenOut = "0xTokenOutAddressHere";
  const amountIn = await app.parseAmount(tokenIn, "1.0");

  return await app.swapExactTokensForTokens({
    tokenIn,
    tokenOut,
    amountIn,
    autoApprove: true,
  });
}